[
  {
    "file": "internal/terraform/evaluate.go",
    "line": 247,
    "severity": "critical",
    "description": "Inverted null check for input variable declaration. The code checks 'if config != nil' but then produces an error saying 'Reference to undeclared input variable'. This is backwards: if config is nil, the variable is undeclared. When config is not nil, the variable IS declared and should not error. This causes legitimate variables to be rejected and non-existent variables to be accepted.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -244,7 +244,7 @@ func (d *evaluationStateData) GetInputVariable(addr addrs.InputVariable, rng tfd
 	}

 	config := moduleConfig.Module.Variables[addr.Name]
-	if config != nil {
+	if config == nil {
 		var suggestions []string
 		for k := range moduleConfig.Module.Variables {
 			suggestions = append(suggestions, k)
"
  },
  {
    "file": "internal/terraform/evaluate.go",
    "line": 281,
    "severity": "critical",
    "description": "Inverted operation walk check. The code checks 'if d.Operation != walkValidate' but then returns unknown values. However, the preceding comment (lines 268-280) clearly states 'During the validate walk, input variables are always unknown'. This should return unknown DURING validate walk, not when NOT in validate walk. This causes actual variable values to be returned during validation instead of unknowns, and unknowns to be returned during plan/apply when real values should be used.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -278,7 +278,7 @@ func (d *evaluationStateData) GetInputVariable(addr addrs.InputVariable, rng tfd
 	// that are disabled, etc. Terraform's static validation leans towards
 	// being liberal in what it accepts because the subsequent plan walk has
 	// more information available and so can be more conservative.
-	if d.Operation != walkValidate {
+	if d.Operation == walkValidate {
 		// We should still capture the statically-configured marks during
 		// the validate walk.
 		ret := cty.UnknownVal(config.Type)
"
  },
  {
    "file": "internal/terraform/evaluate.go",
    "line": 535,
    "severity": "critical",
    "description": "Inverted boolean condition for unknown instance keys. The code checks 'if _, _, hasUnknownKeys := ...; !hasUnknownKeys {' but the comment on the next line says 'There really isn't anything interesting we can do in this situation, because it means we have an unknown for_each/count'. When hasUnknownKeys is true, we DO have unknown keys (the situation described in the comment). The condition should be true when hasUnknownKeys is true, not when it's false. This causes deferred resources with unknown keys to be processed incorrectly.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -532,7 +532,7 @@ func (d *evaluationStateData) GetResource(addr addrs.Resource, rng tfdiags.Sourc
 	// result for _all_ of its work, rather than continuing to duplicate a bunch
 	// of the logic we've tried to encapsulate over ther already.
 	if d.Operation == walkPlan || d.Operation == walkApply {
-		if _, _, hasUnknownKeys := d.Evaluator.Instances.ResourceInstanceKeys(addr.Absolute(moduleAddr)); !hasUnknownKeys {
+		if _, _, hasUnknownKeys := d.Evaluator.Instances.ResourceInstanceKeys(addr.Absolute(moduleAddr)); hasUnknownKeys {
 			// There really isn't anything interesting we can do in this situation,
 			// because it means we have an unknown for_each/count, in which case
 			// we can't even predict what the result type will be because it
"
  },
  {
    "file": "internal/terraform/eval_variable.go",
    "line": 192,
    "severity": "critical",
    "description": "Inverted ephemeral flag condition. The code checks 'if !cfg.Ephemeral' but then marks the value as ephemeral. However, the comment clearly states 'An ephemeral input variable always has an ephemeral value inside the module'. If the variable IS ephemeral (cfg.Ephemeral == true), we should mark it as ephemeral. The current code does the opposite: it marks non-ephemeral variables as ephemeral, causing data integrity issues and incorrect marks on values.",
    "fix_patch": "--- a/internal/terraform/eval_variable.go
+++ b/internal/terraform/eval_variable.go
@@ -189,7 +189,7 @@ func prepareFinalInputVariableValue(addr addrs.AbsInputVariableInstance, raw *In
 		}
 	}

-	if !cfg.Ephemeral {
+	if cfg.Ephemeral {
 		// An ephemeral input variable always has an ephemeral value inside the
 		// module, even if the value assigned to it from outside is not. This
 		// is a useful simplification so that module authors can be explicit
"
  },
  {
    "file": "internal/terraform/hook.go",
    "line": 138,
    "severity": "critical",
    "description": "NilHook.PreApply returns HookActionHalt instead of HookActionContinue. NilHook is a no-op implementation that should never prevent operations from proceeding. All other NilHook methods correctly return HookActionContinue, but PreApply incorrectly returns HookActionHalt. This causes all apply operations to immediately halt when using the default hook implementation, breaking all Terraform applies.",
    "fix_patch": "--- a/internal/terraform/hook.go
+++ b/internal/terraform/hook.go
@@ -135,7 +135,7 @@ type NilHook struct{}
 var _ Hook = (*NilHook)(nil)

 func (*NilHook) PreApply(id HookResourceIdentity, dk addrs.DeposedKey, action plans.Action, priorState, plannedNewState cty.Value) (HookAction, error) {
-	return HookActionHalt, nil
+	return HookActionContinue, nil
 }

 func (*NilHook) PostApply(id HookResourceIdentity, dk addrs.DeposedKey, newState cty.Value, err error) (HookAction, error) {
"
  },
  {
    "file": "internal/terraform/context_apply.go",
    "line": 134,
    "severity": "high",
    "description": "Removed critical validation of apply-time variables. The code previously called checkApplyTimeVariables() which validates that ephemeral variables (apply-time variables) are properly provided during apply. This validation was removed and replaced with a comment saying 'Apply-time variable check handled by graph walk validation.' However, removing explicit validation before graph construction removes an important safety check and pushes all responsibility to the graph walk, which may not catch all errors early.",
    "fix_patch": "--- a/internal/terraform/context_apply.go
+++ b/internal/terraform/context_apply.go
@@ -131,7 +131,13 @@ func (c *Context) ApplyAndEval(plan *plans.Plan, config *configs.Config, opts *A
 	// The caller must provide values for all of the "apply-time variables"
 	// mentioned in the plan, and for no others because the others come from
 	// the plan itself.
-	// Apply-time variable check handled by graph walk validation.
+	diags = diags.Append(checkApplyTimeVariables(plan.ApplyTimeVariables, opts.SetVariables, config))
+
+	if diags.HasErrors() {
+		// If the apply request is invalid in some way then we'll bail out
+		// here before we do any real work.
+		return nil, nil, diags
+	}

 	for _, rc := range plan.Changes.Resources {
 		// Import is a no-op change during an apply (all the real action happens during the plan) but we'd
"
  }
]

